create table dirkspzm32.isi_artikel_hersteller_werk (
    sid                        varchar2(2 char) default '01' not null enable,
    artikel_id                 number(*, 0) not null enable,
    artikel_hersteller_werk_id varchar2(32 char) default sys_guid() not null enable,
    herstellerkuerzel          varchar2(5 char) not null enable,
    werk_id                    varchar2(20 char) not null enable,
    adress_id                  number(*, 0),
    werk_charge_suffix         varchar2(20 char),
    stand_werk                 varchar2(1 char) default 'F'
);

alter table dirkspzm32.isi_artikel_hersteller_werk
    add constraint pk_isi_artikel_hersteller_werk primary key ( artikel_hersteller_werk_id )
        using index enable;


